    if n < 2 * m_spacing + 5:
        return 0.5 * np.log(np.var(residuals) + 1e-8)
    res_sorted = np.sort(residuals)
    diff = res_sorted[2 * m_spacing:] - res_sorted[:-2 * m_spacing]
