                        best_score_new = new_score

        if best_edge is not None and best_gain > 0:
            i, j = best_edge
            adj[i, j] = 0
            current_scores[j] = best_score_new
        else:
            break

    # causallearn convention: B[i, j] != 0 means j -> i
    # Our adj[i, j] == 1 means i -> j. So B = adj.T
    B = adj.T.astype(float)
    return B
